-- ---------- 식물 종 ----------
on conflict (name) do update set image_url = excluded.image_url;

-- ---------- 데모 사용자 ----------
on conflict (email) do nothing;

-- ---------- 데모 내 식물 ----------
on conflict (id) do nothing;

